module top_module(
    // ports
    output wire out,
    input wire in1,
    input wire in2,
    input wire en
);// internal signals
    wire disable_output;

    // 2-to-1 multiplexer
    assign disable_output = (en == 1'b0) ? in1 : in2;

    // output
    assign out = disable_output;

endmodule
